    98→router.get('/getBookmarks', async(req, res) => {
    99→    const {before, limit, userId} = req.query;
   100→
   101→    if(!userId) {
   102→        console.error('no userId')
   103→        return res.status(400).json({error: 'no userId!'})
   104→    }
   105→
   106→    let query = supabase
   107→    .from('bookmarks')
   108→    .select(`*,
   109→        journals(
   110→        id, created_at, user_id, content, title, 
   111→        comment_count: comments(count),
   112→        bookmark_count: bookmarks(count),
   113→
   114→        users(name, user_email, image_url, badge),
   115→
   116→        like_count: likes(count),
   117→        has_liked: likes!left(user_id),
   118→        has_bookmarked: bookmarks!left(user_id)
   119→        )
   120→        `, {count: 'exact'})
   121→
   122→    .eq('user_id', userId)
   123→    .order('created_at', {ascending: false})
   124→    .order('id', {ascending: false})
   125→    .limit(parseInt(limit) + 1) //peek ahead to check if it has more bookmarks
   126→
   127→    if(before) {
   128→        query = query.lt('created_at', before)
   129→    }
   130→    
   131→    const {data: bookmarks, error: errorBookmarks, count} = await query;
   132→    // console.log(bookmarks)
   133→    if(errorBookmarks){
   134→        console.error('supabase error while getting bookmarks:', errorBookmarks);
   135→        return res.status(500).json({error: 'error while fetchin bookmarks from database'});
   136→    }
   137→
   138→    // console.log(bookmarks)
   139→
   140→    const formatted = bookmarks.map((bookmark) => ({
   141→        ...bookmark,
   142→        journals:{
   143→            ...bookmark.journals,
   144→            has_liked: Array.isArray(bookmark.journals?.has_liked) && bookmark?.journals.has_liked.length > 0,
   145→            has_bookmarked: Array.isArray(bookmark?.journals.has_bookmarked) && bookmark?.journals.has_bookmarked.length > 0
   146→        }
   147→    }))
   148→
   149→    const hasMore = bookmarks.length > parseInt(limit);
   150→    const slicedData = hasMore ? formatted.slice(0, parseInt(limit)) : formatted;
   151→
   152→    // console.log(bookmarks);
   153→    
   154→    return res.status(200).json({
   155→        bookmarks: slicedData, 
   156→        hasMore: hasMore, 
   157→        totalBookmarks: before ? null : count});
   158→})
