   323→        console.error('supabase error while fetching comments:', errorFetchComments.message);
   324→        throw {status: 500, error: 'supabase error while fetching comments'}
   325→    }
   326→
   327→    const hasMore = comments.length > parsedLimit;
   328→    const slicedData = hasMore ? comments.splice(0, parsedLimit) : comments;
   329→
   330→    return {comments: comments, hasMore: hasMore};
