   333→export const getOpinionReplyService = async(parentId, limit, before) =>{
   334→    if(!parentId){
   335→        console.error('parentId is undefined');
   336→        throw {status: 400, error: 'parentId is undefined'};
   337→    }
   338→
   339→    if(isNaN(limit) || limit > 20 || limit < 1){
   340→        console.error('limit should be an integer and not more than 20 and less than 1');
   341→        throw {status: 400, error: 'limit should be an integer and not more than 20 and less than 1'};
   342→    }
   343→
   344→    const parsedLimit = parseInt(limit);
   345→
   346→    let query = supabase
   347→    .from('opinions')
   348→    .select('*, users(name, id, user_email, image_url, badge)')
   349→    .eq('parent_id', parentId)
   350→    .order('id', {ascending: false})
   351→    .limit(parsedLimit + 1)
   352→
   353→    if(before){
   354→        query = query.lt('id', before);
   355→    }
   356→    
   357→
   358→    const {data: replyData, error: errorReplyData} = await query;
   359→
   360→    if(errorReplyData){
   361→        console.error('supabase error:', errorReplyData.message);
   362→        throw {status: 500, error: 'supabase error while fetching opinions reply'}
   363→    }
   364→
   365→    const hasMore = replyData.length > parsedLimit;
   366→    const slicedData = hasMore ? replyData.splice(0, parsedLimit) : replyData;
   367→
   368→    return {data: slicedData, hasMore: hasMore};
   369→}

